case_facts = {
    "order_id": "7734",
    "amount_requested": 84.50,
    "currency": "USD",
    "deadline": "2025-03-15",
    "status": "pending_refund",
    "customer_stated_expectation": "reembolso completo antes del 15/3",
}

def construir_prompt(historial_resumido, case_facts, nuevo_mensaje):
    # case_facts va SIEMPRE completo, fuera de cualquier resumen
    bloque_facts = "\n".join(f"- {k}: {v}" for k, v in case_facts.items())
    return f"""
Hechos del caso (siempre exactos, no resumir):
{bloque_facts}

Historial de la conversación (puede estar resumido):
{historial_resumido}

Mensaje nuevo del cliente:
{nuevo_mensaje}
"""

def actualizar_case_facts(case_facts, tool_result):
    # cada resultado de tool que contenga un hecho nuevo actualiza el bloque
    # en vez de quedar enterrado en el historial que luego se resume
    if "refund_amount" in tool_result:
        case_facts["amount_requested"] = tool_result["refund_amount"]
    return case_facts
